import React from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/navigation";
import "swiper/css/pagination";
import "./ProductsDetails.css";
import { EffectFade, Navigation, Pagination, Autoplay } from "swiper/modules";
import { useParams } from "react-router-dom";
function ProductsDetails({ images }) {
  const { ProductId } = useParams();

  return (
    <>
      <Swiper
        rewind={true}
        spaceBetween={30}
        effect={"fade"}
        navigation={true}
        autoplay={{
          delay: 2500,
        }}
        pagination={{
          clickable: true,
          type: "bullets",
        }}
        modules={[EffectFade, Navigation, Pagination, Autoplay]}
        className="mySwiper"
      >
        for (let i = 0; {i < images[ProductId].Images.length}; i++){" "}
        {
          <SwiperSlide key={i}>
            <img src={images[ProductId].Images[i]} alt={"hello"}></img>
          </SwiperSlide>
        }
        {images[ProductId].imgs.map((image, index) => {
          return (
            <SwiperSlide key={index}>
              <img src={image.image} alt={image.title}></img>
            </SwiperSlide>
          );
        })}
      </Swiper>
      <section>
        <h1 style={{ paddingTop: "200px" }}>{images[ProductId].title}</h1>
        <p>Hello guys</p>
      </section>
    </>
  );
}

export default ProductsDetails;
